                        <?php if ( empty( $network_logs ) ) : ?><div class="ms-empty compact"><p>هنوز درخواست خارجی ثبت نشده است.</p></div><?php else : ?><div class="ms-table-wrap"><table class="ms-table"><thead><tr><th>دامنه</th><th>دسته</th><th>کانال</th><th>تصمیم</th><th>وضعیت</th><th>زمان</th><th>تعداد</th></tr></thead><tbody><?php foreach ( $network_logs as $domain => $log ) : $log_category = $categories[ $log['category'] ?? 'unknown' ] ?? $categories['unknown']; ?><tr><td dir="ltr"><?php echo esc_html( $domain ); ?></td><td><?php echo esc_html( $log_category['label'] ); ?></td><td><?php echo 'frontend' === ( $log['channel'] ?? '' ) ? 'فایل Frontend' : 'درخواست سرور'; ?></td><td><?php echo esc_html( $decision_labels[ $log['decision'] ?? 'observe' ] ?? 'ثبت شد' ); ?></td><td dir="ltr"><?php echo esc_html( $log['status'] ?? '—' ); ?></td><td><?php echo null === ( $log['duration'] ?? null ) ? '—' : esc_html( $log['duration'] ) . ' ثانیه'; ?></td><td><?php echo esc_html( $log['count'] ?? 1 ); ?></td></tr><?php endforeach; ?></tbody></table></div><?php endif; ?>
                    </div>
                    <div class="ms-emergency-help"><strong>خاموش‌کردن اضطراری از wp-config.php</strong><code>define( 'MOSTECH_RESILIENCE_EMERGENCY_OFF', true );</code><p>این Constant بر همه تنظیمات مقدم است و در اولین درخواست، مسدودسازی واقعی را متوقف می‌کند.</p></div>
                </section>

                <section id="tab-assets" class="tab-pane"><div class="ms-section-head"><div><span class="eyebrow">اسکن درخواستی و غیرمخرب</span><h2>تصاویر سنگین سایت</h2><p>هیچ فایلی حذف، فشرده یا تبدیل نمی‌شود. نتیجه اسکن یک ساعت Cache می‌شود.</p></div><button class="ms-button ms-scan-images-btn">اسکن تصاویر</button></div><?php if ( ! $heavy_scan_ready ) : ?><div class="ms-empty"><h3>اسکن تصاویر اجرا نشده است</h3><p>برای بررسی uploads و قالب فعال روی «اسکن تصاویر» کلیک کنید.</p></div><?php elseif ( empty( $heavy_images ) ) : ?><div class="ms-empty success"><span>✓</span><h3>تصویر بالای ۲۰۰ کیلوبایت پیدا نشد</h3></div><?php else : ?><?php $image_folders = array_values( array_unique( array_column( $heavy_images, 'folder' ) ) ); $image_types = array_values( array_unique( array_column( $heavy_images, 'extension' ) ) ); sort( $image_folders ); sort( $image_types ); ?><div class="ms-data-toolbar" data-controls="images"><input type="search" id="ms-image-search" placeholder="جست‌وجوی نام فایل…"><select id="ms-image-folder"><option value="">همه پوشه‌ها</option><?php foreach ( $image_folders as $folder ) : ?><option value="<?php echo esc_attr( $folder ); ?>"><?php echo esc_html( $folder ); ?></option><?php endforeach; ?></select><select id="ms-image-type"><option value="">همه نوع‌ها</option><?php foreach ( $image_types as $type ) : ?><option value="<?php echo esc_attr( $type ); ?>"><?php echo esc_html( strtoupper( $type ) ); ?></option><?php endforeach; ?></select><select id="ms-image-origin"><option value="">اصلی و Thumbnail</option><option value="original">فقط تصویر اصلی</option><option value="thumbnail">گروه بدون فایل اصلی</option></select><select id="ms-image-sort"><option value="size-desc">حجم: بیشترین</option><option value="size-asc">حجم: کمترین</option><option value="name">نام فایل</option></select><select id="ms-image-page-size"><option value="20" selected>۲۰ مورد</option><option value="50">۵۰ مورد</option><option value="100">۱۰۰ مورد</option></select></div><div class="ms-panel ms-compact-table"><div class="ms-table-wrap"><table class="ms-table ms-image-table"><thead><tr><th>پیش‌نمایش</th><th>نام فایل</th><th>حجم</th><th>ابعاد</th><th>محل ذخیره</th><th>نوع</th><th>نسخه مرتبط</th><th>پیشنهاد</th></tr></thead><tbody id="ms-image-body"><?php foreach ( $heavy_images as $index => $image ) : $image_detail_id = 'ms-image-detail-' . $index; ?><tr data-image-row data-name="<?php echo esc_attr( strtolower( $image['title'] ) ); ?>" data-folder="<?php echo esc_attr( $image['folder'] ); ?>" data-type="<?php echo esc_attr( $image['extension'] ); ?>" data-origin="<?php echo $image['is_thumbnail'] ? 'thumbnail' : 'original'; ?>" data-bytes="<?php echo esc_attr( $image['bytes'] ); ?>" data-detail="<?php echo esc_attr( $image_detail_id ); ?>"><td><a href="<?php echo esc_url( $image['url'] ); ?>" target="_blank" rel="noopener"><img class="ms-image-thumb" src="<?php echo esc_url( $image['url'] ); ?>" alt="" loading="lazy"></a></td><td><strong dir="ltr"><?php echo esc_html( $image['title'] ?: 'بدون عنوان' ); ?></strong><small class="ms-relative-path" dir="ltr"><?php echo esc_html( $image['relative_path'] ); ?></small></td><td><b><?php echo esc_html( $image['size'] ); ?></b></td><td dir="ltr"><?php echo $image['width'] && $image['height'] ? esc_html( $image['width'] . '×' . $image['height'] . ' px' ) : 'نامشخص'; ?></td><td><?php echo esc_html( $image['source'] ); ?><small class="ms-relative-path"><?php echo esc_html( $image['folder'] ); ?></small></td><td><?php echo $image['is_thumbnail'] ? 'Thumbnail تولیدشده' : 'تصویر اصلی'; ?></td><td><button class="ms-mini-button ms-image-detail-toggle" type="button" aria-expanded="false" aria-controls="<?php echo esc_attr( $image_detail_id ); ?>"><?php echo esc_html( $image['variant_count'] ); ?> نسخه</button></td><td>ابعاد مصرف را بررسی و در صورت نیاز نسخه بهینه را دستی جایگزین کنید.</td></tr><tr id="<?php echo esc_attr( $image_detail_id ); ?>" class="ms-image-detail-row" data-image-detail hidden><td colspan="8"><?php if ( empty( $image['variants'] ) ) : ?><p>نسخه مرتبط سنگین دیگری پیدا نشد.</p><?php else : ?><div class="ms-variant-list"><?php foreach ( $image['variants'] as $variant ) : ?><div><a href="<?php echo esc_url( $variant['url'] ); ?>" target="_blank" rel="noopener" dir="ltr"><?php echo esc_html( $variant['title'] ); ?></a><span><?php echo esc_html( $variant['size'] ); ?></span><span dir="ltr"><?php echo $variant['width'] && $variant['height'] ? esc_html( $variant['width'] . '×' . $variant['height'] . ' px' ) : 'ابعاد نامشخص'; ?></span></div><?php endforeach; ?></div><?php endif; ?></td></tr><?php endforeach; ?></tbody></table></div><div class="ms-pagination"><button class="ms-mini-button" id="ms-image-prev">قبلی</button><span id="ms-image-page-info"></span><button class="ms-mini-button" id="ms-image-next">بعدی</button></div></div><?php endif; ?></section>

                <section id="tab-server" class="tab-pane"><div class="ms-section-head"><div><span class="eyebrow">زیرساخت</span><h2>وضعیت سرور وردپرس</h2></div></div><div class="ms-server-grid"><?php $server_rows = [ 'نسخه PHP' => $server_health['php_version'], 'نسخه وردپرس' => $server_health['wp_version'], 'محدودیت حافظه' => $server_health['memory_limit'], 'OPcache' => $server_health['opcache_active'] ? 'فعال' : 'غیرفعال', 'Object Cache' => $server_health['object_cache'] ? 'فعال' : 'غیرفعال', 'کش صفحه' => $server_health['page_cache'] ? 'اعلام‌شده فعال' : 'اعلام‌نشده', 'افزونه‌های فعال' => $server_health['active_plugins'], 'رویدادهای زمان‌بندی' => $server_health['cron_events'], 'پردازش تصویر' => ( $server_health['gd_active'] || $server_health['imagick_active'] ) ? 'فعال' : 'غیرفعال', 'HTTPS' => $server_health['is_https'] ? 'فعال' : 'غیرفعال', 'فضای خالی' => $server_health['disk_free'] ]; foreach ( $server_rows as $label => $value ) : ?><article><span><?php echo esc_html( $label ); ?></span><strong dir="auto"><?php echo esc_html( $value ); ?></strong></article><?php endforeach; ?></div></section>

                <section id="tab-academy" class="tab-pane">
                    <div class="ms-section-head"><div><span class="eyebrow">راهنمای کامل و ساده</span><h2>آموزش استفاده امن از افزونه</h2><p>اگر با دامنه، درخواست خارجی یا فهرست مسدود (Blocklist) آشنا نیستید، از بخش اول شروع کنید.</p></div></div>
                    <details class="ms-quick-start" open><summary>شروع سریع DepGuard</summary><div><ol><li>حالت پایش را فعال نگه دارید.</li><li>اسکن را اجرا کنید.</li><li>سایت را مرور کنید.</li><li>دامنه‌های ضروری را بررسی کنید.</li><li>حالت شبیه‌سازی را اجرا کنید.</li><li>فقط روی محیط آزمایشی (Staging) تست ۵ دقیقه‌ای انجام دهید.</li></ol><div class="ms-quick-actions"><button class="ms-button" data-open-tab="external">رفتن به تحلیل دامنه‌ها</button><button class="ms-button secondary" data-open-tab="network">رفتن به حالت شبیه‌سازی</button><button class="ms-button ghost" data-open-emergency>مشاهده روش خاموش‌کردن اضطراری</button></div></div></details>
                    <div class="ms-quick-paths"><button data-open-lesson="1"><b>اولین بار است استفاده می‌کنم</b><span>از معرفی و مسیر امن شروع کنید.</span></button><button data-open-tab="external"><b>می‌خواهم یک دامنه را بررسی کنم</b><span>جدول، فیلترها و جزئیات دامنه را باز کنید.</span></button><button data-open-emergency><b>بعد از مسدودسازی سایت مشکل دارد</b><span>حالت پایش و خاموش‌کن اضطراری را ببینید.</span></button></div>
                    <div class="ms-academy-lessons">
                        <details class="ms-lesson" data-lesson="1"><summary><span>۱</span><div><b>این افزونه چه کاری انجام می‌دهد؟</b><small>شناسایی ارتباط‌هایی که در اختلال اینترنت ممکن است سایت را کند یا ناقص کنند.</small></div></summary><div class="ms-lesson-body"><p>سایت وردپرسی ممکن است برای فونت، پیامک، پرداخت، نقشه، آمار، لایسنس و فایل‌ها به سایت‌های دیگر متصل شود. کندی یا قطعی آن سرویس‌ها می‌تواند انتظار طولانی یا خرابی یک بخش را ایجاد کند.</p><p>افزونه این وابستگی‌ها را شناسایی می‌کند تا مدیر اثرشان را بررسی و برای هر دامنه قانون روشن تعیین کند. این ابزار کش، Minify، ترکیب فایل یا جایگزین WP Rocket نیست.</p></div></details>
                        <details class="ms-lesson"><summary><span>۲</span><div><b>وابستگی خارجی چیست؟</b><small>هر فایل یا سرویسی که از دامنه‌ای غیر از سایت شما دریافت شود.</small></div></summary><div class="ms-lesson-body"><div class="ms-sensitive-grid"><span>Google Fonts</span><span>سرویس پیامک</span><span>درگاه پرداخت</span><span>نقشه</span><span>CDN فایل‌ها</span><span>بررسی لایسنس</span></div><p>مثلاً فونت گوگل از سرور گوگل، نقشه از سرویس نقشه و تأیید تراکنش از درگاه پرداخت می‌آید. همه وابستگی‌های خارجی بد نیستند؛ پرداخت، پیامک ورود یا لایسنس ممکن است برای عملکرد سایت ضروری باشند.</p></div></details>
                        <details class="ms-lesson"><summary><span>۳</span><div><b>سه حالت افزونه</b><small>از پایش شروع کنید؛ فقط حالت اجرایی می‌تواند قطع واقعی انجام دهد.</small></div></summary><div class="ms-lesson-body"><div class="ms-edu-mode-grid"><article><b>پایش — امن‌ترین</b><p>هیچ چیزی قطع نمی‌شود. برای اولین استفاده و جمع‌آوری اطلاعات مناسب است.</p></article><article><b>شبیه‌سازی</b><p>چیزی قطع نمی‌شود؛ فقط نشان می‌دهد کدام دامنه Blocklist در حالت اجرایی قطع خواهد شد.</p></article><article class="danger"><b>اجرایی آزمایشی</b><p>دامنه‌های Blocklist واقعاً و برای زمان محدود قطع می‌شوند. ابتدا روی سایت آزمایشی استفاده کنید.</p></article></div></div></details>
                        <details class="ms-lesson"><summary><span>۴</span><div><b>فهرست مجاز و فهرست مسدود چیست؟</b><small>Allowlist با Blocklist رفتار متفاوتی دارد.</small></div></summary><div class="ms-lesson-body"><div class="ms-edu-example safe"><b>فهرست مجاز (Allowlist)</b><p>دامنه مورد اعتماد است و افزونه آن را مسدود نمی‌کند؛ نمونه: درگاه پرداخت ضروری.</p></div><div class="ms-edu-example warning"><b>فهرست مسدود (Blocklist)</b><p>نمونه: سرویس آمار غیرضروری که پس از تست تصمیم گرفته‌اید در اختلال قطع شود.</p></div><div class="ms-edu-example"><b>بدون قانون</b><p>دامنه فقط پایش می‌شود و مسدود نخواهد شد. فهرست مسدود در حالت پایش و شبیه‌سازی هم قطع واقعی ایجاد نمی‌کند.</p></div></div></details>
                        <details class="ms-lesson"><summary><span>۵</span><div><b>آموزش استفاده قدم‌به‌قدم</b><small>از نصب تا یک آزمایش اجرایی پنج‌دقیقه‌ای.</small></div></summary><div class="ms-lesson-body"><ol class="ms-steps"><li>افزونه را نصب و فعال کنید.</li><li>وارد صفحه «DepGuard» شوید.</li><li>حالت را روی «پایش» نگه دارید.</li><li>دکمه اسکن صفحه اصلی را بزنید.</li><li>چند بخش مهم سایت را باز کنید تا ارتباطات سروری ثبت شوند.</li><li>دامنه‌های شناسایی‌شده را بررسی کنید.</li><li>دسته‌بندی، نوع مشاهده و اثر قطع هر دامنه را بخوانید.</li><li>دامنه‌های ضروری را وارد فهرست مجاز (Allowlist) کنید.</li><li>فقط دامنه‌های غیرضروری و شناخته‌شده را وارد فهرست مسدود (Blocklist) کنید.</li><li>حالت شبیه‌سازی را فعال کنید.</li><li>صفحه اصلی، ورود، فرم‌ها، سبد خرید و تسویه را تست کنید.</li><li>فقط پس از اطمینان، حالت اجرایی ۵ دقیقه‌ای را روی محیط آزمایشی (Staging) فعال کنید.</li><li>پس از پایان، گزارش و خطاها را بررسی کنید.</li></ol></div></details>
                        <details class="ms-lesson"><summary><span>۶</span><div><b>قبل از مسدودسازی چه چیزهایی را بررسی کنیم؟</b><small>این چک‌لیست را پیش از آزمایش اجرایی کامل کنید.</small></div></summary><div class="ms-lesson-body"><ul class="ms-checklist interactive"><li><label><input type="checkbox"> از سایت نسخه پشتیبان دارید.</label></li><li><label><input type="checkbox"> تست روی محیط آزمایشی (Staging) انجام می‌شود.</label></li><li><label><input type="checkbox"> دامنه درگاه پرداخت شناسایی شده است.</label></li><li><label><input type="checkbox"> سرویس پیامک و ورود شناسایی شده‌اند.</label></li><li><label><input type="checkbox"> صفحه ورود و فرم تماس تست شده‌اند.</label></li><li><label><input type="checkbox"> سبد خرید و تسویه‌حساب تست شده‌اند.</label></li><li><label><input type="checkbox"> پنل مدیریت در یک تب دیگر باز است.</label></li><li><label><input type="checkbox"> روش خاموش‌کردن اضطراری را می‌دانید.</label></li></ul></div></details>
                        <details class="ms-lesson" id="ms-emergency-lesson"><summary><span>۷</span><div><b>خاموش‌کردن اضطراری</b><small>راه بازگشت حتی وقتی پیشخوان در دسترس نیست.</small></div></summary><div class="ms-lesson-body"><p>خط زیر را پیش از عبارت پایان ویرایش در فایل <code>wp-config.php</code> قرار دهید:</p><pre><code>define( 'MOSTECH_RESILIENCE_EMERGENCY_OFF', true );</code></pre><p>این ثابت بر همه تنظیمات مقدم است و در اولین درخواست بعدی حالت اجرایی را متوقف می‌کند. پس از رفع مشکل می‌توانید مقدار را <code>false</code> کنید یا خط را حذف کنید.</p></div></details>
                        <details class="ms-lesson"><summary><span>۸</span><div><b>چهار مثال قابل فهم</b><small>کاربرد، اثر قطع، قانون معمول و تست لازم.</small></div></summary><div class="ms-lesson-body ms-example-grid"><div class="ms-edu-example"><b>فونت گوگل</b><p><b>کار:</b> نمایش فونت. <b>اثر قطع:</b> فونت جایگزین یا تأخیر. <b>قانون معمول:</b> پس از میزبانی محلی، Blocklist؛ وگرنه Allowlist. <b>تست:</b> ظاهر موبایل و دسکتاپ.</p></div><div class="ms-edu-example"><b>سرویس آمار</b><p><b>کار:</b> ثبت بازدید. <b>اثر قطع:</b> آمار ثبت نمی‌شود. <b>قانون معمول:</b> اگر غیرضروری است Blocklist. <b>تست:</b> عملکرد فرم و خرید بدون آن.</p></div><div class="ms-edu-example safe"><b>درگاه پرداخت</b><p><b>کار:</b> پرداخت و تأیید تراکنش. <b>اثر قطع:</b> خرید ناموفق. <b>قانون معمول:</b> Allowlist. <b>تست:</b> پرداخت و بازگشت از درگاه آزمایشی.</p></div><div class="ms-edu-example safe"><b>سرویس پیامک</b><p><b>کار:</b> کد ورود یا اعلان سفارش. <b>اثر قطع:</b> پیامک نمی‌رسد. <b>قانون معمول:</b> در صورت نیاز Allowlist. <b>تست:</b> ورود یک‌بارمصرف و پیام سفارش.</p></div></div></details>
                        <details class="ms-lesson"><summary><span>۹</span><div><b>خطاهای رایج</b><small>اشتباه‌هایی که پیش از اجرای واقعی باید از آن‌ها جلوگیری کنید.</small></div></summary><div class="ms-lesson-body"><ul><li><b>درگاه پرداخت در Blocklist:</b> آن را به Allowlist منتقل و فرایند پرداخت را تست کنید.</li><li><b>فعال‌کردن مستقیم حالت اجرایی:</b> ابتدا پایش و شبیه‌سازی را کامل کنید.</li><li><b>تصور اینکه Allowlist بقیه را قطع می‌کند:</b> دامنه بدون قانون فقط پایش می‌شود.</li><li><b>اعتماد کامل به دسته‌بندی خودکار:</b> کاربرد دامنه را بررسی و دسته را دستی اصلاح کنید.</li><li><b>تست‌نکردن موبایل، ورود و Checkout:</b> همه مسیرهای حیاتی را در چک‌لیست بررسی کنید.</li><li><b>استفاده مستقیم روی سایت اصلی:</b> ابتدا روی Staging و فقط برای ۵ دقیقه آزمایش کنید.</li></ul></div></details>
                        <details class="ms-lesson"><summary><span>۱۰</span><div><b>واژه‌نامه ساده</b><small>معنی کوتاه اصطلاح‌های مورد استفاده در افزونه.</small></div></summary><div class="ms-lesson-body ms-glossary-grid"><div><b>دامنه</b><p>نام یک سایت یا سرویس، مثل api.example.com.</p></div><div><b>درخواست خارجی</b><p>ارتباط سایت با دامنه‌ای غیر از دامنه خودش.</p></div><div><b>رابط برنامه‌نویسی (API)</b><p>راه استاندارد ارتباط دو نرم‌افزار با یکدیگر.</p></div><div><b>شبکه توزیع محتوا (CDN)</b><p>شبکه توزیع فایل‌هایی مثل CSS، JavaScript و تصویر.</p></div><div><b>فهرست مجاز (Allowlist)</b><p>دامنه‌های مجاز که مسدود نمی‌شوند.</p></div><div><b>فهرست مسدود (Blocklist)</b><p>دامنه‌هایی که فقط در حالت اجرایی قطع می‌شوند.</p></div><div><b>حالت پایش</b><p>ثبت و تحلیل بدون هیچ قطع واقعی.</p></div><div><b>حالت شبیه‌سازی</b><p>نمایش موارد قابل قطع بدون تغییر رفتار سایت.</p></div><div><b>حالت اجرایی</b><p>قطع موقت دامنه‌های Blocklist پس از تأیید مدیر.</p></div><div><b>درخواست بازگشتی داخلی (Loopback)</b><p>درخواست وردپرس به خود سایت؛ مسدود نمی‌شود.</p></div><div><b>رابط REST وردپرس (REST API)</b><p>رابط داخلی وردپرس برای تبادل داده؛ مسدود نمی‌شود.</p></div><div><b>زمان‌بند وردپرس (WP-Cron)</b><p>اجرای کارهای دوره‌ای وردپرس.</p></div><div><b>محیط آزمایشی (Staging)</b><p>نسخه جدا از سایت اصلی برای تست امن.</p></div></div></details>
                    </div>
                </section>
            </main>
